fun solve(landStartTime: Array<Long>, landDuration: Array<Long>, waterStartTime: Array<Long>, waterDuration: Array<Long>): Long {
    // Calculate all possible end times for land and water attractions
    val landEndTimes = landStartTime.mapIndexed { i, startTime ->
        maxOf(startTime, startTime + landDuration[i])
    }

    val waterEndTimes = waterStartTime.mapIndexed { j, startTime ->
        maxOf(startTime, startTime + waterDuration[j])
    }

    // Try all combinations of one land and one water attraction
    var minTime = Long.MAX_VALUE

    for (landEndTime in landEndTimes) {
        for (waterEndTime in waterEndTimes) {
            // If the land attraction ends before the water starts, the water can start immediately
            val time1 = if (landEndTime <= waterEndTime) waterEndTime else landEndTime + waterDuration[0]
            // If the water attraction ends before the land starts, the land can start immediately
            val time2 = if (waterEndTime <= landEndTime) landEndTime else waterEndTime + landDuration[0]
            minTime = minOf(minTime, time1, time2)
        }
    }

    return minTime
}
